    expect(format('FROM t |> WHERE x > 1')).toBe(dedent`
      FROM
        t
      |> WHERE
        x > 1
    `);
  });

  it('formats AGGREGATE with a nested GROUP BY sub-clause', () => {
    expect(
      format(
