      FROM
        produce
      |> AGGREGATE
        COUNT(*) AS num_items,
        SUM(sales) AS total_sales
        GROUP BY
          item
    `);
  });

  it('formats AGGREGATE without a GROUP BY', () => {
    expect(format('FROM produce |> AGGREGATE COUNT(*) AS num_items')).toBe(dedent`
      FROM
        produce
      |> AGGREGATE
        COUNT(*) AS num_items
    `);
  });

  it('formats EXTEND, SET and DROP as indented clauses', () => {
    expect(format('FROM t |> EXTEND a + b AS c |> SET x = 3 |> DROP y')).toBe(dedent`
      FROM
        t
      |> EXTEND
        a + b AS c
      |> SET
        x = 3
      |> DROP
        y
    `);
  });

  it('formats ORDER BY as an indented clause', () => {
    expect(format('FROM t |> ORDER BY a DESC, b')).toBe(dedent`
      FROM
        t
      |> ORDER BY
        a DESC,
        b
    `);
  });

  it('formats LIMIT as a one-line clause', () => {
    expect(format('FROM t |> LIMIT 10')).toBe(dedent`
      FROM
        t
      |> LIMIT 10
    `);
  });

  it('formats AS as a one-line clause', () => {
    expect(format('FROM t |> AS renamed')).toBe(dedent`
      FROM
        t
      |> AS renamed
    `);
  });

